import React, { useEffect, useRef } from 'react';

const StudioBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let particles: Array<{
      x: number;
      y: number;
      size: number;
      speedY: number;
      speedX: number;
      opacity: number;
      color: string;
    }> = [];

    const colors = [
      '14, 165, 233', // Sky-500
      '59, 130, 246', // Blue-500
      '99, 102, 241', // Indigo-500
      '148, 163, 184', // Slate-400
    ];

    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      initParticles();
    };

    const createParticle = (bottom = false) => {
        const x = Math.random() * canvas.width;
        // Start randomly on screen, or at bottom if respawning
        const y = bottom ? canvas.height + Math.random() * 20 : Math.random() * canvas.height;
        const size = Math.random() * 3 + 0.5;
        // Upward speed (anti-gravity)
        const speedY = Math.random() * 0.5 + 0.2; 
        const speedX = (Math.random() - 0.5) * 0.2;
        const opacity = Math.random() * 0.4 + 0.1;
        const color = colors[Math.floor(Math.random() * colors.length)];

        return { x, y, size, speedY, speedX, opacity, color };
    };

    const initParticles = () => {
      const particleCount = Math.floor((canvas.width * canvas.height) / 10000);
      particles = [];
      for (let i = 0; i < particleCount; i++) {
        particles.push(createParticle());
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach((p, i) => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${p.color}, ${p.opacity})`;
        ctx.fill();

        // Update position - Move Upwards
        p.y -= p.speedY;
        p.x += p.speedX;

        // Reset if it goes off top
        if (p.y < -10) {
            particles[i] = createParticle(true);
        }
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();
    draw();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="fixed top-0 left-0 w-full h-full pointer-events-none -z-10"
      style={{ background: 'linear-gradient(to bottom, #f0f9ff, #ffffff)' }} // Soft sky gradient
    />
  );
};

