    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let columns: Array<{
      x: number;
      speed: number;
      offset: number;
      width: number;
      color: string;
    }> = [];

    // Industrial/Tech colors
    const colors = [
      '148, 163, 184', // Slate-400
      '59, 130, 246',  // Blue-500
      '100, 116, 139', // Slate-500
      '71, 85, 105',   // Slate-600
    ];

    const initColumns = () => {
      columns = [];
      const colWidth = 50; // Width of the tread
      const gap = 40;      // Gap between treads
      const totalWidth = canvas.width;
      // Calculate how many columns fit
      const numCols = Math.ceil(totalWidth / (colWidth + gap));

      for (let i = 0; i < numCols; i++) {
        columns.push({
          x: i * (colWidth + gap) + gap / 2,
          width: colWidth,
          // Random speed between 0.2 and 0.8, random direction up or down
          speed: (Math.random() * 0.6 + 0.2) * (Math.random() > 0.5 ? 1 : -1), 
          offset: Math.random() * 200,
          color: colors[Math.floor(Math.random() * colors.length)],
        });
      }
    };

    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      initColumns();
    };

    const drawTreadShape = (x: number, y: number, width: number, height: number, color: string) => {
        ctx.beginPath();

        // Draw a Chevron / Tread shape
        //   \      /
        //    \    /
        //     \  /
        //      \/
        const thickness = 12;
        const midX = x + width / 2;

        ctx.moveTo(x, y);
        ctx.lineTo(midX, y + height); // Point down
        ctx.lineTo(x + width, y);
        ctx.lineTo(x + width, y + thickness);
        ctx.lineTo(midX, y + height + thickness);
        ctx.lineTo(x, y + thickness);

        ctx.closePath();

        ctx.fillStyle = `rgba(${color}, 0.15)`; // Subtle transparent overlay
        ctx.fill();
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const treadHeight = 30; // Height of one V shape
      const treadGap = 20;    // Vertical gap between shapes
      const totalItemHeight = treadHeight + treadGap;

      columns.forEach(col => {
        // Move column
        col.offset += col.speed;

        // Wrap offset to create infinite scroll illusion
        if (col.offset > totalItemHeight) col.offset -= totalItemHeight;
        if (col.offset < 0) col.offset += totalItemHeight;

        // Calculate how many items to draw to cover the screen height plus buffers
        const numRows = Math.ceil(canvas.height / totalItemHeight) + 2;

        for (let j = -1; j < numRows; j++) {
            // Calculate Y position based on row index and column offset
            const y = (j * totalItemHeight) + (col.offset % totalItemHeight);

            drawTreadShape(col.x, y, col.width, treadHeight, col.color);
        }
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();
    draw();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="fixed top-0 left-0 w-full h-full pointer-events-none z-30"
    />
  );
};

