// --- Router Implementation ---
// Replacing react-router-dom due to missing module errors.

const RouterContext = createContext<{ pathname: string }>({ pathname: '/' });

export const useLocation = () => useContext(RouterContext);

export const HashRouter: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [pathname, setPathname] = useState(window.location.hash.slice(1) || '/');

  useEffect(() => {
    const handleHashChange = () => {
      // Ensure we treat empty hash as root
      const path = window.location.hash.slice(1) || '/';
      setPathname(path);
    };
    window.addEventListener('hashchange', handleHashChange);

    // Set initial hash if empty
    if (!window.location.hash) {
        window.history.replaceState(null, '', '#/');
        setPathname('/');
    }

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  return (
    <RouterContext.Provider value={{ pathname }}>
      {children}
    </RouterContext.Provider>
  );
};

export const Link: React.FC<React.AnchorHTMLAttributes<HTMLAnchorElement> & { to: string }> = ({ to, children, ...props }) => {
  // Construct hash based link
  const href = to.startsWith('#') ? to : `#${to}`;
  return (
    <a href={href} {...props}>
      {children}
    </a>
  );
};

export const Outlet: React.FC = () => null;

