                                    key={subItem.title}
                                    to={subItem.href}
                                    onClick={() => setIsMobileMenuOpen(false)}
                                    className="block py-2 px-3 text-sm font-medium text-slate-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
