import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Zap, Search, ChevronRight, User, LogOut } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { useAuth } from '../../../context/AuthContext';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // If the click is not on a dropdown button AND not inside the menu container, close menus
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') && 
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // Reset search when active submenu changes
  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    // Prevent the document click listener from firing immediately
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  const handleLogout = () => {
    logout();
    navigate('/');
    setIsMobileMenuOpen(false);
  };

  // Helper to filter items based on search query
  const getFilteredItems = (megaMenu: any, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col: any) => {
      if (col.items) {
        col.items.forEach((item: any) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group: any) => {
          group.items.forEach((item: any) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  const activeItem = NAV_ITEMS.find(item => item.title === activeSubmenu);

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/90 backdrop-blur-md shadow-sm py-4' : 'bg-transparent py-6'
        }`}
    >
      {/* Added 'relative' to the container to position absolute mega-menus correctly */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between h-12">

          {/* Logo on Left */}
          <div className="flex-shrink-0 z-20">
            <Link to="/" className="flex items-center gap-2 cursor-pointer group">
              <img src="https://www.gnjworldwide.com/Logo.png" className="h-10 w-auto" alt="GnJ Worldwide Logo" />
            </Link>
          </div>

          {/* Menu Items in Center - Absolutely Positioned Pill */}
          <div className="hidden lg:flex absolute left-1/2 top-1/2 transform -translate-x-1/2 -translate-y-1/2 z-10">
            <div className={`flex items-center gap-1 px-4 py-1.5 rounded-full transition-all duration-300 ${scrolled ? 'bg-slate-100/50 border border-slate-200/50' : 'bg-white/40 backdrop-blur-md border border-white/40 shadow-sm'}`}>
              {NAV_ITEMS.map((item) => (
                <div
                  key={item.title}
                  className="relative"
                >
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-[14px] font-semibold rounded-full transition-all duration-200 group ${activeSubmenu === item.title
                        ? 'text-slate-900 bg-white shadow-sm'
                        : 'text-slate-700 hover:text-slate-900 hover:bg-white/50'
                        }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1 w-3.5 h-3.5 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : 'text-slate-400 group-hover:text-slate-600'
                          }`}
                      />
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-4 py-2 text-[14px] font-semibold text-slate-700 rounded-full hover:text-slate-900 hover:bg-white/50 transition-all duration-200"
                    >
                      {item.title}
                    </Link>
                  )}

                  {/* Regular Dropdown (Non-Mega) */}
                  {item.children && !item.megaMenu && activeSubmenu === item.title && (
                    <div className="absolute top-full left-1/2 transform -translate-x-1/2 mt-4 w-60 bg-white rounded-2xl shadow-xl border border-slate-200 py-3 z-50 animate-fade-in-up">
                      {item.children.map((subItem) => (
                        <Link
                          key={subItem.title}
                          to={subItem.href}
                          onClick={() => setActiveSubmenu(null)}
                          className="flex items-center px-6 py-3 text-sm font-medium text-slate-600 hover:bg-slate-50 hover:text-blue-600 transition-colors"
                        >
                          {subItem.title}
                        </Link>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right Side Actions */}
          <div className="hidden lg:flex items-center gap-4 z-20">
            <button
              className="p-2.5 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>

            {isAuthenticated ? (
                <div className="flex items-center gap-3 pl-2 border-l border-slate-200">
                    <div className="text-right">
                        <div className="text-xs font-bold text-slate-900">{user?.name}</div>
                        <div className="text-[10px] text-slate-500">Member</div>
                    </div>
                    <button 
                        onClick={handleLogout}
                        className="p-2 bg-slate-100 text-slate-600 hover:bg-red-50 hover:text-red-600 rounded-full transition-colors"
                        title="Logout"
                    >
                        <LogOut size={18} />
                    </button>
                </div>
            ) : (
                <div className="flex items-center gap-2">
                    <Link 
                        to="/login"
                        className="px-4 py-2 text-sm font-bold text-slate-600 hover:text-slate-900 transition-colors"
                    >
                        Log in
                    </Link>
                    <Link 
                        to="/signup"
                        className="px-4 py-2 text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-full transition-colors"
                    >
                        Sign up
                    </Link>
                </div>
            )}

            <Link 
              to="/contact"
              className="relative overflow-hidden group bg-slate-900 hover:bg-slate-800 text-white text-sm font-bold py-2.5 px-6 rounded-full transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-lg ml-2"
            >
              <span className="relative z-10 flex items-center gap-2">
                Contact <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform"/>
              </span>
            </Link>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2 z-20">
            <button
              className="p-2 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-colors"
              aria-label="Search"
            >
              <Search size={22} />
            </button>

            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>

        {/* Mega Menu Dropdown (Rendered at container level for full width) */}
        {activeItem?.megaMenu && activeSubmenu === activeItem.title && (
            <div className="absolute top-16 left-0 w-full pt-4 z-40 animate-slide-down">
                {/* Invisible bridge to prevent mouseleave issues */}
                <div className="absolute top-0 left-0 w-full h-4 bg-transparent"></div>

                {/* Added 'relative' to allow absolute positioning of the close button inside */}
                <div className="bg-sky-50 shadow-2xl rounded-3xl border border-slate-200 overflow-hidden mega-menu-container relative">

                {/* Close Button - Moved to top right corner and made smaller */}
                <button
                    onClick={(e) => { e.stopPropagation(); setActiveSubmenu(null); }}
                    className="absolute top-2 right-2 p-1 bg-white rounded-full text-slate-400 hover:text-slate-600 hover:bg-slate-100 transition-all z-50 shadow-sm"
                >
                    <X size={14} />
                </button>

                {/* Search Bar Area */}
                <div className="px-8 pt-8 pb-2">
                    <div className="relative">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                        <input 
                            type="text" 
                            placeholder={`Find in ${activeItem.title}...`}
                            className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 focus:border-yellow-400 transition-all text-sm font-medium text-slate-700 placeholder:text-slate-400 shadow-sm"
                            value={menuSearchQuery}
                            onChange={(e) => setMenuSearchQuery(e.target.value)}
                            autoFocus
                            onClick={(e) => e.stopPropagation()}
                        />
                    </div>
                </div>

                {menuSearchQuery ? (
                    // Search Results View
                    <div className="p-8 min-h-[250px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
                    {(() => {
                        const results = getFilteredItems(activeItem.megaMenu, menuSearchQuery);
                        return results.length > 0 ? (
                            <div>
                                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Search Results ({results.length})</h4>
                                <div className="grid grid-cols-3 gap-4">
                                    {results.map((res, idx) => (
                                        <Link 
                                            key={idx} 
                                            to={res.href}
