                    </div>
                )}
                </div>
            </div>
        )}
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50 bg-white animate-fade-in flex flex-col">
