                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                        <input 
                            type="text" 
                            placeholder={`Find in ${activeItem.title}...`}
                            className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 focus:border-yellow-400 transition-all text-sm font-medium text-slate-700 placeholder:text-slate-400 shadow-sm"
                            value={menuSearchQuery}
                            onChange={(e) => setMenuSearchQuery(e.target.value)}
                            autoFocus
                            onClick={(e) => e.stopPropagation()}
                        />
                    </div>
                </div>

                {menuSearchQuery ? (
                    // Search Results View
                    <div className="p-8 min-h-[250px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
                    {(() => {
                        const results = getFilteredItems(activeItem.megaMenu, menuSearchQuery);
                        return results.length > 0 ? (
                            <div>
                                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Search Results ({results.length})</h4>
                                <div className="grid grid-cols-3 gap-4">
                                    {results.map((res, idx) => (
                                        <Link 
                                            key={idx} 
                                            to={res.href}
                                            onClick={() => setActiveSubmenu(null)}
