          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-2 z-20">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-lg text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors focus:outline-none"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>

        {/* Mega Menu Dropdown (Rendered at container level for full width) */}
        {activeItem?.megaMenu && activeSubmenu === activeItem.title && (
            <div className="absolute top-16 left-0 w-full pt-4 z-40 animate-slide-down">
                {/* Invisible bridge to prevent mouseleave issues */}
                <div className="absolute top-0 left-0 w-full h-4 bg-transparent"></div>

                {/* Added 'relative' to allow absolute positioning of the close button inside */}
                <div className="bg-sky-50 shadow-2xl rounded-3xl border border-slate-200 overflow-hidden mega-menu-container relative">

                {/* Close Button - Moved to top right corner and made smaller */}
                <button
                    onClick={(e) => { e.stopPropagation(); setActiveSubmenu(null); }}
                    className="absolute top-2 right-2 p-1 bg-white rounded-full text-slate-400 hover:text-slate-600 hover:bg-slate-100 transition-all z-50 shadow-sm"
                >
                    <X size={14} />
