import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { ChevronDown, Menu, X } from 'lucide-react';
import { NAV_ITEMS } from './constants';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [activeMegaMenu, setActiveMegaMenu] = useState<string | null>(null);
  const { pathname } = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    setMobileMenuOpen(false);
    setActiveMegaMenu(null);
  }, [pathname]);

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        isScrolled || mobileMenuOpen ? 'bg-white/80 backdrop-blur-md shadow-sm border-b border-slate-200/50' : 'bg-transparent'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2 z-50">
             <img src="https://www.gnjworldwide.com/Logo.png" className="h-8 w-auto" alt="GnJ Logo" />
             <span className={`font-bold text-xl tracking-tight transition-colors ${isScrolled || mobileMenuOpen ? 'text-slate-900' : 'text-slate-900'}`}>
                GnJ<span className="text-yellow-500">Worldwide</span>
             </span>
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden lg:flex items-center gap-1">
            {NAV_ITEMS.map((item) => (
              <div
                key={item.title}
                className="relative group"
                onMouseEnter={() => setActiveMegaMenu(item.title)}
                onMouseLeave={() => setActiveMegaMenu(null)}
              >
                <Link
                  to={item.href}
                  className={`px-4 py-2 rounded-full text-sm font-medium flex items-center gap-1 transition-all ${
                    activeMegaMenu === item.title 
                      ? 'bg-slate-100 text-blue-600' 
                      : 'text-slate-600 hover:text-slate-900 hover:bg-slate-50'
                  }`}
                >
                  {item.title}
                  {item.megaMenu && <ChevronDown size={14} className={`transition-transform duration-300 ${activeMegaMenu === item.title ? 'rotate-180' : ''}`} />}
                </Link>

                {/* Mega Menu Dropdown */}
                {item.megaMenu && activeMegaMenu === item.title && (
                  <div className="absolute top-full left-1/2 transform -translate-x-1/2 pt-4 w-screen max-w-7xl px-4 sm:px-6 lg:px-8">
                    <div className="bg-white rounded-2xl shadow-2xl border border-slate-100 p-8 grid grid-cols-5 gap-8 animate-fade-in-up">
                       {/* Columns */}
                       {item.megaMenu.columns.map((col, idx) => (
                         <div key={idx} className="space-y-6">
                            {col.title && <h3 className="font-bold text-slate-900 text-sm uppercase tracking-wider">{col.title}</h3>}

                            {col.items && (
                              <ul className="space-y-3">
                                {col.items.map((link) => (
                                  <li key={link.title}>
                                    <Link to={link.href} className="text-sm text-slate-600 hover:text-blue-600 hover:translate-x-1 transition-all block">
                                      {link.title}
                                    </Link>
                                  </li>
                                ))}
                              </ul>
                            )}

                            {col.groups && col.groups.map((group, gIdx) => (
                               <div key={gIdx} className="mb-6">
                                  <h4 className="font-bold text-slate-900 text-sm mb-3">{group.title}</h4>
                                  <ul className="space-y-2">
                                    {group.items.map((link) => (
                                      <li key={link.title}>
                                        <Link to={link.href} className="text-sm text-slate-600 hover:text-blue-600 hover:translate-x-1 transition-all block">
                                          {link.title}
                                        </Link>
                                      </li>
                                    ))}
                                  </ul>
                               </div>
                            ))}
                         </div>
                       ))}
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* Action Buttons */}
          <div className="hidden lg:flex items-center gap-4">
             <div className="flex items-center p-1 bg-white/90 backdrop-blur-sm border border-slate-200/80 rounded-full shadow-sm hover:shadow-md transition-all duration-300">
                <Link 
                    to="/login"
                    className="px-5 py-2 text-sm font-bold text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-all"
                >
                    Log in
                </Link>
                <Link 
                    to="/signup"
                    className="ml-1 px-6 py-2 text-sm font-bold text-white bg-slate-900 hover:bg-slate-800 rounded-full shadow-md transition-all hover:scale-105 active:scale-95"
