                        </Link>
                        <Link to="/signup" onClick={() => setIsMobileMenuOpen(false)} className="text-center py-2.5 rounded-xl bg-blue-600 text-white font-bold">
                            Sign Up
                        </Link>
                    </div>
                )}
            </div>

            <div className="flex-1 overflow-y-auto py-2 px-4 space-y-2">
              {NAV_ITEMS.map((item) => (
