                        className="px-5 py-2 text-sm font-bold text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full transition-all"
                    >
                        Log in
                    </Link>
                    <Link 
                        to="/signup"
                        className="ml-1 px-6 py-2 text-sm font-bold text-white bg-slate-900 hover:bg-slate-800 rounded-full shadow-md transition-all hover:scale-105 active:scale-95"
                    >
                        Sign up
                    </Link>
                </div>
            )}

            <Link 
              to="/contact"
              className="relative overflow-hidden group bg-slate-900 hover:bg-slate-800 text-white text-sm font-bold py-2.5 px-6 rounded-full transition-all duration-300 transform hover:-translate-y-0.5 hover:shadow-lg ml-2"
            >
              <span className="relative z-10 flex items-center gap-2">
                Contact <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform"/>
              </span>
            </Link>
