                <img src="https://www.gnjworldwide.com/Logo.png" className="h-8 w-auto" alt="Logo" />
                <span className="font-bold text-lg text-slate-900">GnJ<span className="text-yellow-500">Worldwide</span></span>
              </div>
              <button
