import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Search, LogOut, ChevronRight } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { useAuth } from '../../../context/AuthContext';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') &&
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  const handleLogout = () => {
    logout();
    navigate('/');
    setIsMobileMenuOpen(false);
  };

  const getFilteredItems = (megaMenu: any, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col: any) => {
      if (col.items) {
        col.items.forEach((item: any) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group: any) => {
          group.items.forEach((item: any) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  const activeItem = NAV_ITEMS.find(item => item.title === activeSubmenu);
  let searchResults: { title: string; href: string; context?: string }[] = [];
  if (activeItem?.megaMenu && menuSearchQuery) {
    searchResults = getFilteredItems(activeItem.megaMenu, menuSearchQuery);
  }

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ease-in-out ${scrolled ? 'py-2' : 'py-6'
        }`}
    >
      <div className={`max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative transition-all duration-500`}>
        <div className={`flex items-center justify-between transition-all duration-300 ${scrolled 
            ? 'glass-panel rounded-full pl-6 pr-2 py-2 shadow-lg shadow-blue-900/5' 
            : 'bg-transparent py-0'
        }`}>

          {/* Logo */}
          <div className="flex-shrink-0 flex items-center gap-8">
            <Link to="/" className="flex items-center gap-2 cursor-pointer group">
              <img src="https://www.gnjworldwide.com/Logo.png" className="h-8 w-auto transition-transform duration-300 group-hover:scale-105" alt="GnJ Logo" />
              <span className={`font-bold text-lg tracking-tight transition-colors ${scrolled ? 'text-slate-900' : 'text-slate-900'}`}>
                GnJ<span className="text-yellow-500">Worldwide</span>
              </span>
            </Link>

            {/* Desktop Menu */}
            <div className="hidden lg:flex items-center gap-1">
              {NAV_ITEMS.map((item) => (
                <div key={item.title} className="relative">
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-4 py-2 text-sm font-semibold rounded-full transition-all duration-300 group ${activeSubmenu === item.title
                          ? 'bg-slate-100 text-slate-900 ring-1 ring-slate-200'
                          : 'text-slate-600 hover:text-slate-900 hover:bg-slate-100/50'
                        }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1 w-3.5 h-3.5 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : 'text-slate-400 group-hover:text-slate-600'
                          }`}
                      />
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-4 py-2 text-sm font-semibold text-slate-600 rounded-full hover:text-slate-900 hover:bg-slate-100/50 transition-all duration-300"
                    >
                      {item.title}
                    </Link>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right Actions */}
          <div className="hidden lg:flex items-center gap-3">
            {isAuthenticated ? (
              <div className="flex items-center gap-3 pl-4 border-l border-slate-200">
                <div className="text-right">
                  <div className="text-xs font-bold text-slate-900">{user?.name}</div>
                  <div className="text-[10px] text-slate-500">Member</div>
                </div>
                <button
                  onClick={handleLogout}
                  className="p-2 bg-slate-100 text-slate-600 hover:bg-red-50 hover:text-red-600 rounded-full transition-colors"
                  title="Logout"
                >
                  <LogOut size={16} />
                </button>
              </div>
            ) : (
              <div className="flex items-center">
                <Link
                  to="/login"
                  className="px-5 py-2 text-sm font-bold text-slate-600 hover:text-blue-600 transition-colors"
                >
                  Log in
                </Link>
                <Link
                  to="/contact"
                  className="bg-slate-900 hover:bg-blue-600 text-white text-sm font-bold py-2.5 px-6 rounded-full transition-all duration-300 shadow-md hover:shadow-lg transform hover:-translate-y-0.5 flex items-center gap-2 group"
                >
                  Contact <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
                </Link>
              </div>
            )}
          </div>

          {/* Mobile Toggle */}
          <div className="lg:hidden flex items-center">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="p-2 text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>

        {/* Mega Menu Container - Attached nicely */}
        {activeItem?.megaMenu && activeSubmenu === activeItem.title && (
          <div className="absolute top-full left-0 w-full pt-4 z-40 mega-menu-container">
            <div className="bg-white/95 backdrop-blur-xl shadow-2xl rounded-2xl border border-white/50 overflow-hidden animate-slide-down origin-top">

              {/* Close & Search */}
              <div className="px-8 pt-6 pb-2 flex justify-between items-center border-b border-slate-100/50">
                 <div className="relative w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input
                      type="text"
                      placeholder={`Find in ${activeItem.title}...`}
                      className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-transparent hover:border-slate-200 focus:border-blue-500 rounded-lg focus:outline-none transition-all text-sm"
                      value={menuSearchQuery}
                      onChange={(e) => setMenuSearchQuery(e.target.value)}
                      autoFocus
                      onClick={(e) => e.stopPropagation()}
                    />
                 </div>
                 <button
                    onClick={(e) => { e.stopPropagation(); setActiveSubmenu(null); }}
                    className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                  >
                    <X size={20} />
                  </button>
              </div>

              <div className="max-h-[70vh] overflow-y-auto custom-scrollbar">
                {menuSearchQuery ? (
                  <div className="p-8">
                    {searchResults.length > 0 ? (
                      <div className="grid grid-cols-3 gap-4">
                        {searchResults.map((res, idx) => (
                          <Link
                            key={idx}
                            to={res.href}
                            onClick={() => setActiveSubmenu(null)}
                            className="flex flex-col p-4 rounded-xl bg-slate-50 hover:bg-blue-50 hover:scale-[1.02] transition-all duration-200 group"
                          >
                            <span className="font-bold text-slate-900 group-hover:text-blue-600 mb-1 flex justify-between items-center">
                              {res.title}
                              <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0"/>
                            </span>
                            {res.context && <span className="text-xs text-slate-500">{res.context}</span>}
                          </Link>
                        ))}
                      </div>
                    ) : (
                      <div className="py-12 text-center text-slate-500">No matches found.</div>
                    )}
                  </div>
                ) : (
                  <div className="flex p-8 gap-8">
                    {/* Featured Left Panel */}
                    {activeItem.megaMenu.leftContent && (
                      <div className="w-72 flex-shrink-0 relative overflow-hidden rounded-xl bg-gradient-to-br from-slate-900 to-blue-900 p-8 text-white flex flex-col shadow-lg">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500 rounded-full blur-3xl opacity-20 -mr-10 -mt-10"></div>
                        <div className="absolute bottom-0 left-0 w-32 h-32 bg-yellow-500 rounded-full blur-3xl opacity-20 -ml-10 -mb-10"></div>

                        {activeItem.megaMenu.leftContent.badgeText && (
                          <span className="inline-block px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-xs font-bold mb-4 w-fit">
                            {activeItem.megaMenu.leftContent.badgeText}
                          </span>
                        )}
                        <h3 className="font-bold text-2xl mb-2 relative z-10">{activeItem.megaMenu.leftContent.title}</h3>
                        <p className="text-sm text-slate-300 mb-6 relative z-10 leading-relaxed">{activeItem.megaMenu.leftContent.description}</p>

                        {activeItem.megaMenu.leftContent.image && (
                           <div className="mt-auto rounded-lg overflow-hidden relative h-32">
                              <img src={activeItem.megaMenu.leftContent.image} className="object-cover w-full h-full opacity-80 mix-blend-overlay hover:scale-110 transition-transform duration-700" alt="Feature"/>
                           </div>
                        )}
                      </div>
                    )}

                    {/* Links Grid */}
                    <div className="flex-1 grid grid-cols-4 gap-8">
                      {activeItem.megaMenu.columns.map((column, idx) => (
                        <div key={idx} className="space-y-6">
                          {column.groups ? (
                            column.groups.map((group, gIdx) => (
                              <div key={gIdx}>
                                {group.title && <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">{group.title}</h4>}
                                <ul className="space-y-2">
                                  {group.items.map((subItem, sIdx) => (
                                    <li key={sIdx}>
                                      <Link
                                        to={subItem.href}
                                        onClick={() => setActiveSubmenu(null)}
                                        className="block text-sm font-medium text-slate-600 hover:text-blue-600 hover:translate-x-1 transition-all duration-200"
                                      >
                                        {subItem.title}
                                      </Link>
                                    </li>
                                  ))}
                                </ul>
                              </div>
                            ))
                          ) : (
                            <div>
                              {column.title && <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">{column.title}</h4>}
                              <ul className="space-y-2">
                                {column.items?.map((subItem, sIdx) => (
                                  <li key={sIdx}>
                                    <Link
                                      to={subItem.href}
                                      onClick={() => setActiveSubmenu(null)}
                                      className="block text-sm font-medium text-slate-600 hover:text-blue-600 hover:translate-x-1 transition-all duration-200"
                                    >
                                      {subItem.title}
                                    </Link>
                                  </li>
                                ))}
                              </ul>
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-50 bg-white animate-fade-in flex flex-col">
           {/* Mobile header and content same as before, simplified for brevity in this update */}
           <div className="flex items-center justify-between p-4 border-b border-gray-100">
              <span className="font-bold text-lg text-slate-900">GnJ<span className="text-yellow-500">Worldwide</span></span>
              <button onClick={() => setIsMobileMenuOpen(false)} className="p-2"><X size={24} /></button>
           </div>
           <div className="flex-1 overflow-y-auto p-4">
              {NAV_ITEMS.map((item) => (
                 <div key={item.title} className="mb-4">
                    <div className="font-bold text-lg mb-2 text-slate-900">{item.title}</div>
                    {item.children && <div className="pl-4 border-l-2 border-slate-100 space-y-2">
                        {item.children.map(child => <Link key={child.title} to={child.href} onClick={() => setIsMobileMenuOpen(false)} className="block text-slate-600">{child.title}</Link>)}
                    </div>}
                    {item.megaMenu && <div className="pl-4 border-l-2 border-slate-100 space-y-2">
                        {item.megaMenu.columns.map(col => col.items?.map(sub => <Link key={sub.title} to={sub.href} onClick={() => setIsMobileMenuOpen(false)} className="block text-slate-600">{sub.title}</Link>))}
                    </div>}
                 </div>
              ))}
           </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

