                              </h4>
                            ) : group.title === "" ? (
                              // Render spacer if empty string
                              <h4 className="text-[13px] font-bold text-transparent border-b border-transparent pb-2 select-none" aria-hidden="true">
                                &nbsp;
                              </h4>
                            ) : null}

                            <ul className="space-y-1">
                              {group.items.map((subItem, sIdx) => (
                                <li key={sIdx}>
                                  <Link
                                    to={subItem.href}
