                  className="flex items-center justify-between w-full px-4 py-3 text-base font-semibold text-slate-800 rounded-xl hover:bg-slate-50 cursor-pointer active:bg-slate-100 transition-colors"
                  onClick={() => {
                    if (item.children || item.megaMenu) {
                      setActiveSubmenu(activeSubmenu === item.title ? null : item.title);
                    } else {
                      setIsMobileMenuOpen(false);
                    }
                  }}
                >
                  {item.children || item.megaMenu ? (
                    <span>{item.title}</span>
                  ) : (
                    <Link to={item.href} onClick={() => setIsMobileMenuOpen(false)}>
                      {item.title}
                    </Link>
                  )}

                  {(item.children || item.megaMenu) && (
                    <ChevronDown
                      className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${activeSubmenu === item.title ? 'rotate-180 text-yellow-500' : ''}`}
                    />
                  )}
                </div>

                {/* Mobile Submenu Rendering */}
                {activeSubmenu === item.title && (
                  <div className="pl-4 pr-2 py-2 space-y-1 bg-slate-50/50 rounded-xl mt-1">
                    {item.megaMenu ? (
                      item.megaMenu.columns.map((col, idx) => (
                        <div key={idx} className="mb-4">
                          {col.groups ? (
                            col.groups.map((group, gIdx) => (
                              <div key={gIdx} className="mb-4">
                                {group.title && (
                                  <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 px-3">{group.title}</h5>
                                )}
                                {group.items.map(subItem => (
                                  <Link
                                    key={subItem.title}
                                    to={subItem.href}
                                    onClick={() => setIsMobileMenuOpen(false)}
                                    className="block py-2 px-3 text-sm font-medium text-slate-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                  >
                                    {subItem.title}
                                  </Link>
                                ))}
                              </div>
                            ))
                          ) : (
                            <>
                              {col.title && (
                                <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 px-3">{col.title}</h5>
                              )}
                              {col.items?.map(subItem => (
                                <Link
                                  key={subItem.title}
                                  to={subItem.href}
                                  onClick={() => setIsMobileMenuOpen(false)}
                                  className="block py-2 px-3 text-sm font-medium text-slate-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                >
                                  {subItem.title}
                                </Link>
                              ))}
                            </>
                          )}
                        </div>
                      ))
                    ) : (
                      item.children?.map((subItem) => (
                        <Link
                          key={subItem.title}
                          to={subItem.href}
                          onClick={() => setIsMobileMenuOpen(false)}
                          className="block py-2 px-3 text-sm font-medium text-slate-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        >
                          {subItem.title}
                        </Link>
                      ))
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>

          <div className="p-4 border-t border-gray-100">
            <Link to="/contact" onClick={() => setIsMobileMenuOpen(false)} className="w-full flex justify-center items-center bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold py-4 rounded-2xl transition-all shadow-lg active:scale-95">
              Contact Us <ArrowRight className="ml-2 w-5 h-5" />
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, ArrowRight, Search, LogOut, ChevronRight } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { NAV_ITEMS } from './constants';
import { useAuth } from '../../../context/AuthContext';

const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSubmenu, setActiveSubmenu] = useState<string | null>(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuSearchQuery, setMenuSearchQuery] = useState('');

  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();

  // Handle scroll effect for sticky navbar shadow/height
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close submenu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        !(event.target as HTMLElement).closest('button[data-menu-trigger]') &&
        !(event.target as HTMLElement).closest('.mega-menu-container')
      ) {
        setActiveSubmenu(null);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // Reset search when active submenu changes
  useEffect(() => {
    setMenuSearchQuery('');
  }, [activeSubmenu]);

  const toggleSubmenu = (title: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setActiveSubmenu(prev => prev === title ? null : title);
  };

  const handleLogout = () => {
    logout();
    navigate('/');
    setIsMobileMenuOpen(false);
  };

  const getFilteredItems = (megaMenu: any, query: string) => {
    if (!query) return [];
    const lowerQ = query.toLowerCase();
    const results: { title: string; href: string; context?: string }[] = [];

    megaMenu.columns.forEach((col: any) => {
      if (col.items) {
        col.items.forEach((item: any) => {
          if (item.title.toLowerCase().includes(lowerQ)) {
            results.push({ ...item, context: col.title });
          }
        });
      }
      if (col.groups) {
        col.groups.forEach((group: any) => {
          group.items.forEach((item: any) => {
            if (item.title.toLowerCase().includes(lowerQ)) {
              results.push({ ...item, context: group.title });
            }
          });
        });
      }
    });
    return results;
  };

  const activeItem = NAV_ITEMS.find(item => item.title === activeSubmenu);

  let searchResults: { title: string; href: string; context?: string }[] = [];
  if (activeItem?.megaMenu && menuSearchQuery) {
    searchResults = getFilteredItems(activeItem.megaMenu, menuSearchQuery);
  }

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 font-sans ${
        scrolled 
          ? 'bg-white/90 backdrop-blur-xl shadow-sm py-3' 
          : 'bg-transparent py-5'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <div className="flex items-center justify-between h-14">

          {/* Left: Logo */}
          <div className="flex-shrink-0 flex items-center z-20">
            <Link to="/" className="flex items-center gap-2 cursor-pointer group" onClick={() => setActiveSubmenu(null)}>
              <img src="https://www.gnjworldwide.com/Logo.png" className="h-10 w-auto transition-transform group-hover:scale-105" alt="GnJ Worldwide Logo" />
              <div className={`hidden sm:flex flex-col leading-none font-bold text-xl tracking-tight text-slate-900`}>
                 <span>GnJ<span className="text-yellow-500">Worldwide</span></span>
              </div>
            </Link>
          </div>

          {/* Center: Menu Items */}
          <div className="hidden lg:flex absolute left-1/2 top-1/2 transform -translate-x-1/2 -translate-y-1/2">
            <div className={`flex items-center gap-2 px-3 py-2 rounded-full transition-all duration-300 ${
              scrolled ? 'bg-white/50 border border-slate-100' : 'bg-white/80 backdrop-blur-md shadow-sm border border-white/50'
            }`}>
              {NAV_ITEMS.map((item) => (
                <div key={item.title} className="relative">
                  {item.children || item.megaMenu ? (
                    <button
                      data-menu-trigger="true"
                      onClick={(e) => toggleSubmenu(item.title, e)}
                      className={`flex items-center px-5 py-2.5 text-sm font-semibold rounded-full transition-all duration-300 group ${
                        activeSubmenu === item.title
                          ? 'bg-black text-white shadow-md'
                          : 'text-slate-700 hover:bg-black hover:text-white'
                      }`}
                    >
                      {item.title}
                      <ChevronDown
                        className={`ml-1.5 w-4 h-4 transition-transform duration-300 ${
                          activeSubmenu === item.title ? 'rotate-180 text-yellow-400' : 'text-slate-400 group-hover:text-white'
                        }`}
                      />
                    </button>
                  ) : (
                    <Link
                      to={item.href}
                      className="flex items-center px-5 py-2.5 text-sm font-semibold text-slate-700 rounded-full hover:bg-black hover:text-white transition-all duration-300"
                    >
                      {item.title}
                    </Link>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right: Actions */}
          <div className="hidden lg:flex items-center gap-4 z-20">
            {isAuthenticated ? (
              <div className="flex items-center gap-3 pl-2">
                <div className="text-right hidden xl:block">
                  <div className="text-xs font-bold text-slate-900">{user?.name}</div>
                  <div className="text-[10px] text-slate-500">Member</div>
                </div>
                <button
                  onClick={handleLogout}
                  className="p-2.5 bg-slate-100 text-slate-600 hover:bg-red-50 hover:text-red-600 rounded-full transition-colors border border-slate-200"
                  title="Logout"
                >
                  <LogOut size={18} />
                </button>
              </div>
            ) : (
              <div className="flex items-center gap-1">
                <Link
                  to="/login"
                  className="px-4 py-2 text-sm font-bold text-slate-600 hover:text-slate-900 transition-colors"
                >
                  Log in
                </Link>
                <Link
                  to="/signup"
                  className="px-5 py-2.5 text-sm font-bold text-slate-900 bg-yellow-400 hover:bg-yellow-500 rounded-full transition-all shadow-sm hover:shadow-md"
                >
                  Sign up
                </Link>
              </div>
            )}

            <Link
              to="/contact"
              className="relative overflow-hidden group bg-slate-900 hover:bg-slate-800 text-white text-sm font-bold py-2.5 px-6 rounded-full transition-all duration-300 shadow-lg hover:shadow-slate-500/30"
            >
              <span className="relative z-10 flex items-center gap-2">
                Contact <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
              </span>
            </Link>
          </div>

          {/* Mobile Actions */}
          <div className="lg:hidden flex items-center gap-3 z-20">
             {isAuthenticated && (
                <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-xs">
                    {user?.name.charAt(0)}
                </div>
             )}
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2.5 rounded-full text-slate-700 hover:bg-slate-100 transition-colors focus:outline-none border border-slate-200 bg-white"
            >
              {isMobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
            </button>
          </div>
        </div>

        {/* Mega Menu Dropdown */}
        {activeItem?.megaMenu && activeSubmenu === activeItem.title && (
          <div className="absolute top-full left-0 w-full bg-white shadow-[0_20px_50px_-12px_rgba(0,0,0,0.1)] border-t border-slate-100 z-40 animate-slide-down mega-menu-container rounded-b-3xl mt-4">

            <div className="max-w-7xl mx-auto">
              <div className="flex flex-col">

                {/* Search Header */}
                <div className="px-8 pt-6 pb-2 border-b border-slate-50">
                   <div className="relative max-w-md mx-auto">
                      <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                      <input
                        type="text"
                        placeholder={`Search in ${activeItem.title}...`}
                        className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-full text-sm font-medium focus:outline-none focus:ring-2 focus:ring-slate-200 transition-all placeholder:text-slate-400"
                        value={menuSearchQuery}
                        onChange={(e) => setMenuSearchQuery(e.target.value)}
                        onClick={(e) => e.stopPropagation()}
                        autoFocus
                      />
                   </div>
                </div>

                {menuSearchQuery ? (
                  // Search Results
                  <div className="p-10 min-h-[300px] max-h-[60vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
                    {searchResults.length > 0 ? (
                      <div>
                        <div className="flex items-center justify-between mb-6">
                            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Results for "{menuSearchQuery}"</h4>
                            <span className="text-xs font-bold text-slate-300">{searchResults.length} matches</span>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                          {searchResults.map((res, idx) => (
                            <Link
                              key={idx}
                              to={res.href}
                              onClick={() => setActiveSubmenu(null)}
                              className="group flex flex-col p-5 rounded-xl border border-slate-100 bg-white hover:border-slate-200 hover:shadow-lg transition-all duration-300"
                            >
                              <span className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors mb-1 text-sm flex items-center justify-between">
                                {res.title}
                                <ChevronRight size={14} className="text-slate-300 opacity-0 group-hover:opacity-100 transform -translate-x-2 group-hover:translate-x-0 transition-all" />
                              </span>
                              {res.context && <span className="text-xs text-slate-500 font-medium bg-slate-50 w-fit px-2 py-0.5 rounded mt-2">{res.context}</span>}
                            </Link>
                          ))}
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center py-16 text-slate-400">
                        <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                          <Search size={24} className="text-slate-300" />
                        </div>
                        <p className="font-medium text-slate-500">No results found</p>
                      </div>
                    )}
                  </div>
                ) : (
                  // Main Mega Menu Content
                  <div className="flex flex-row px-10 py-12 gap-16" onClick={(e) => e.stopPropagation()}>

                    {/* Left Featured Content (Optional) */}
                    {activeItem.megaMenu.leftContent && (
                      <div className="w-64 flex-shrink-0">
                        <div className="bg-slate-50 rounded-2xl p-6 h-full border border-slate-100 hover:shadow-md transition-all group relative overflow-hidden">
                           {activeItem.megaMenu.leftContent.badgeText && (
                              <span className="inline-block px-2.5 py-1 bg-yellow-400 text-slate-900 text-[10px] font-bold uppercase tracking-wide rounded-full mb-4">
                                 {activeItem.megaMenu.leftContent.badgeText}
                              </span>
