                                  <h4 className="text-[11px] font-extrabold text-slate-400 uppercase tracking-widest border-b border-slate-100 pb-2">
                                    {group.title}
                                  </h4>
                                ) : group.title === "" ? (
                                  <div className="h-6"></div>
                                ) : null}

                                <ul className="space-y-3">
                                  {group.items.map((subItem, sIdx) => (
                                    <li key={sIdx}>
                                      <Link
                                        to={subItem.href}
                                        onClick={() => setActiveSubmenu(null)}
                                        className="group/link block"
                                      >
                                        <span className="text-[15px] font-medium text-slate-600 group-hover/link:text-blue-600 group-hover/link:translate-x-1 transition-all inline-block">
